# --- Error Classification ---

class ErrorCategory(Enum):
    """Classifies errors for appropriate client-facing messages."""
    VALIDATION = "validation"
    NOT_FOUND = "not_found"
    PERMISSION = "permission"
    RATE_LIMIT = "rate_limit"
    DEPENDENCY = "dependency"
    INTERNAL = "internal"


# Maps error categories to gRPC status codes
CATEGORY_TO_GRPC_CODE = {
    ErrorCategory.VALIDATION: grpc.StatusCode.INVALID_ARGUMENT,
    ErrorCategory.NOT_FOUND: grpc.StatusCode.NOT_FOUND,
    ErrorCategory.PERMISSION: grpc.StatusCode.PERMISSION_DENIED,
    ErrorCategory.RATE_LIMIT: grpc.StatusCode.RESOURCE_EXHAUSTED,
    ErrorCategory.DEPENDENCY: grpc.StatusCode.UNAVAILABLE,
    ErrorCategory.INTERNAL: grpc.StatusCode.INTERNAL,
}

# Safe client-facing messages per category (no internal details)
CATEGORY_TO_CLIENT_MESSAGE = {
    ErrorCategory.VALIDATION: "Invalid request parameters.",
    ErrorCategory.NOT_FOUND: "The requested resource was not found.",
    ErrorCategory.PERMISSION: "You do not have permission to perform this action.",
    ErrorCategory.RATE_LIMIT: "Rate limit exceeded. Please retry later.",
    ErrorCategory.DEPENDENCY: "A downstream service is temporarily unavailable. Please retry.",
    ErrorCategory.INTERNAL: "An internal error occurred. Please contact support.",
}


# --- Custom Exceptions ---

class ServiceError(Exception):
    """Base exception for service-layer errors with safe classification."""

    def __init__(
        self,
        message: str,
        category: ErrorCategory = ErrorCategory.INTERNAL,
        safe_detail: Optional[str] = None,
    ):
        super().__init__(message)
        self.category = category
        # Optional additional safe detail to send to client
        self.safe_detail = safe_detail


class ValidationError(ServiceError):
    def __init__(self, message: str, safe_detail: Optional[str] = None):
        super().__init__(message, ErrorCategory.VALIDATION, safe_detail)


class NotFoundError(ServiceError):
    def __init__(self, message: str, safe_detail: Optional[str] = None):
        super().__init__(message, ErrorCategory.NOT_FOUND, safe_detail)


class DependencyError(ServiceError):
    def __init__(self, message: str, safe_detail: Optional[str] = None):
        super().__init__(message, ErrorCategory.DEPENDENCY, safe_detail)


# --- Error Context for Server-Side Logging ---

@dataclass
class ErrorContext:
    """Captures full error context for server-side logging only."""
    correlation_id: str
    method_name: str
    exception_type: str
    exception_message: str
    stack_trace: str
    internal_state: dict = field(default_factory=dict)
    request_metadata: dict = field(default_factory=dict)
    timestamp: float = 0.0
    category: ErrorCategory = ErrorCategory.INTERNAL

    def to_log_dict(self) -> dict:
        """Convert to dictionary for structured logging."""
        return {
            "correlation_id": self.correlation_id,
            "method": self.method_name,
            "error_type": self.exception_type,
            "error_message": self.exception_message,
            "stack_trace": self.stack_trace,
            "internal_state": self.internal_state,
            "request_metadata": self.request_metadata,
            "timestamp": self.timestamp,
            "category": self.category.value,
        }


# --- Secure Error Handler ---

class SecureErrorHandler:
    """
    Handles errors securely:
    - Logs full details server-side (stack traces, internal state)
    - Returns only safe, sanitized messages to clients
    - Uses correlation IDs to link client errors to server logs
    """

    @staticmethod
    def generate_correlation_id() -> str:
        return str(uuid.uuid4())

    @staticmethod
    def extract_safe_metadata(context: ServicerContext) -> dict:
        """Extract metadata safe for server-side logging."""
        metadata = {}
        try:
            invocation_metadata = context.invocation_metadata()
            if invocation_metadata:
                # Only log non-sensitive headers
                safe_keys = {"user-agent", "x-request-id", "x-correlation-id"}
                for key, value in invocation_metadata:
                    if key.lower() in safe_keys:
                        metadata[key] = value
        except Exception:
            pass
        return metadata

    @classmethod
    def handle_error(
        cls,
        context: ServicerContext,
        exception: Exception,
        method_name: str,
        internal_state: Optional[dict] = None,
    ) -> None:
        """
        Process an exception securely:
        1. Generate correlation ID
        2. Log full details server-side
        3. Send safe message + correlation ID to client
        """
        correlation_id = cls.generate_correlation_id()

        # Classify the error
        if isinstance(exception, ServiceError):
            category = exception.category
            safe_detail = exception.safe_detail
        else:
            category = cls._classify_unknown_exception(exception)
            safe_detail = None

        # Build full error context for server-side logging
        error_ctx = ErrorContext(
            correlation_id=correlation_id,
            method_name=method_name,
            exception_type=type(exception).__name__,
            exception_message=str(exception),
            stack_trace=traceback.format_exc(),
            internal_state=internal_state or {},
            request_metadata=cls.extract_safe_metadata(context),
            timestamp=time.time(),
            category=category,
        )

        # Log FULL details server-side (this is where developers debug)
        cls._log_error_server_side(error_ctx)

        # Send SAFE message to client
        grpc_code = CATEGORY_TO_GRPC_CODE.get(category, grpc.StatusCode.INTERNAL)
        client_message = cls._build_client_message(
            correlation_id, category, safe_detail
        )

        context.set_code(grpc_code)
        context.set_details(client_message)

        # Add correlation ID as trailing metadata so clients can reference it
        context.set_trailing_metadata([
            ("x-correlation-id", correlation_id),
        ])

    @classmethod
    def _classify_unknown_exception(cls, exception: Exception) -> ErrorCategory:
        """Classify non-ServiceError exceptions by type."""
        if isinstance(exception, (ValueError, TypeError, KeyError)):
            return ErrorCategory.VALIDATION
        if isinstance(exception, PermissionError):
            return ErrorCategory.PERMISSION
        if isinstance(exception, (ConnectionError, TimeoutError, OSError)):
            return ErrorCategory.DEPENDENCY
        return ErrorCategory.INTERNAL

    @classmethod
    def _log_error_server_side(cls, error_ctx: ErrorContext) -> None:
        """
        Log complete error details server-side.
        In production, this would go to a centralized logging system
        (e.g., ELK, Datadog, CloudWatch) for searching by correlation_id.
        """
        log_data = error_ctx.to_log_dict()

        if error_ctx.category == ErrorCategory.INTERNAL:
            debug_logger.error(
                "INTERNAL ERROR [%s] in %s: %s\n"
                "Full state: %s\n"
                "Stack trace:\n%s",
                error_ctx.correlation_id,
                error_ctx.method_name,
                error_ctx.exception_message,
                error_ctx.internal_state,
                error_ctx.stack_trace,
            )
        else:
            debug_logger.warning(
                "SERVICE ERROR [%s] in %s (%s): %s\n"
                "State: %s",
                error_ctx.correlation_id,
                error_ctx.method_name,
                error_ctx.category.value,
                error_ctx.exception_message,
                error_ctx.internal_state,
            )

    @classmethod
    def _build_client_message(
        cls,
        correlation_id: str,
        category: ErrorCategory,
        safe_detail: Optional[str] = None,
    ) -> str:
        """Build a safe client-facing error message."""
        base_message = CATEGORY_TO_CLIENT_MESSAGE.get(
            category, "An unexpected error occurred."
        )
        parts = [base_message]
        if safe_detail:
            parts.append(safe_detail)
        parts.append(f"Correlation ID: {correlation_id}")
        return " | ".join(parts)


# --- Decorator for Service Methods ---

def secure_grpc_method(method_name: Optional[str] = None):
    """
    Decorator that wraps gRPC service methods with secure error handling.
    Catches all exceptions, logs details server-side, returns safe messages.
    """
    def decorator(func):
        @wraps(func)
        def wrapper(self, request, context: ServicerContext):
            resolved_name = method_name or func.__name__
            try:
                return func(self, request, context)
            except ServiceError as e:
                # Known service errors - log and return safe message
                internal_state = {}
                if hasattr(self, '_get_debug_state'):
                    internal_state = self._get_debug_state()
                SecureErrorHandler.handle_error(
                    context, e, resolved_name, internal_state
                )
                return None
            except Exception as e:
                # Unknown errors - log full details, return generic message
                internal_state = {}
                if hasattr(self, '_get_debug_state'):
                    internal_state = self._get_debug_state()
                SecureErrorHandler.handle_error(
                    context, e, resolved_name, internal_state
                )
                return None
        return wrapper
    return decorator


