class DatabaseClient:
    """Simulated database client."""

    def __init__(self):
        self._connected = True
        self._query_count = 0

    def get_user(self, user_id: str) -> Optional[dict]:
        self._query_count += 1
        if not self._connected:
            raise ConnectionError("Database connection lost")
        if user_id == "error":
            raise RuntimeError("Unexpected database error on row scan")
        if user_id == "missing":
            return None
        return {"user_id": user_id, "name": "Alice", "email": "alice@example.com"}

    def get_order(self, order_id: str) -> Optional[dict]:
        self._query_count += 1
        if order_id == "timeout":
            raise TimeoutError("Query timed out after 30s")
        if order_id == "missing":
            return None
        return {"order_id": order_id, "status": "shipped", "user_id": "user123"}

    def get_state(self) -> dict:
        return {
            "connected": self._connected,
            "query_count": self._query_count,
        }


