# --- gRPC Service Implementation ---

class UserServiceServicer:
    """
    Example gRPC service with secure error handling.

    All errors are:
    - Fully logged server-side with stack traces and internal state
    - Returned to clients with only safe messages and correlation IDs
    """

    def __init__(self):
        self._db = DatabaseClient()
        self._cache = CacheClient()
        self._request_count = 0

    def _get_debug_state(self) -> dict:
        """
        Gather internal state for server-side debugging.
        This is NEVER sent to clients.
        """
        return {
            "service": "UserService",
            "request_count": self._request_count,
            "db_state": self._db.get_state(),
            "cache_state": self._cache.get_state(),
        }

    @secure_grpc_method(method_name="GetUser")
    def GetUser(self, request: demo_pb2.UserRequest, context: ServicerContext):
        self._request_count += 1

        # Input validation
        if not request.user_id:
            raise ValidationError(
                "user_id field is empty",
                safe_detail="The 'user_id' field is required."
            )

        if len(request.user_id) > 128:
            raise ValidationError(
                f"user_id too long: {len(request.user_id)} chars",
                safe_detail="The 'user_id' field exceeds maximum length."
            )

        # Check cache first
        cached = self._cache.get(f"user:{request.user_id}")
        if cached:
            return cached

        # Query database (may raise ConnectionError, RuntimeError, etc.)
        user_data = self._db.get_user(request.user_id)

        if user_data is None:
            raise NotFoundError(
                f"User not found in DB: user_id={request.user_id}",
                safe_detail=f"User '{request.user_id}' was not found."
            )

        return demo_pb2.UserResponse(
            user_id=user_data["user_id"],
            name=user_data["name"],
            email=user_data["email"],
        )

    @secure_grpc_method(method_name="GetOrder")
    def GetOrder(self, request: demo_pb2.OrderRequest, context: ServicerContext):
        self._request_count += 1

        if not request.order_id:
            raise ValidationError(
                "order_id is empty",
                safe_detail="The 'order_id' field is required."
            )

        order_data = self._db.get_order(request.order_id)

        if order_data is None:
            raise NotFoundError(
                f"Order not found: order_id={request.order_id}",
                safe_detail=f"Order '{request.order_id}' was not found."
            )

        return demo_pb2.OrderResponse(
            order_id=order_data["order_id"],
            status=order_data["status"],
        )

    @secure_grpc_method(method_name="HealthCheck")
    def HealthCheck(self, request, context: ServicerContext):
        return demo_pb2.HealthResponse(
            status="healthy",
            timestamp=time.time(),
        )


# --- Server Setup ---

def create_server(port: int = 50051, max_workers: int = 10) -> grpc.Server:
    """Create and configure the gRPC server."""
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        options=[
            ("grpc.max_send_message_length", 10 * 1024 * 1024),  # 10MB
            ("grpc.max_receive_message_length", 10 * 1024 * 1024),
        ],
    )

    # In production, register with generated add_*_to_server function
    # demo_pb2_grpc.add_UserServiceServicer_to_server(UserServiceServicer(), server)

    server.add_insecure_port(f"[::]:{port}")
    return server


